import{_ as e,c as l,o,a as i}from"./app.50048430.js";const g=JSON.parse('{"title":"Date \u6784\u9020\u5668","description":"","frontmatter":{"title":"Date \u6784\u9020\u5668","date":"2017-06-19T00:00:00.000Z","tags":["JS"]},"headers":[{"level":2,"title":"\u672F\u8BED","slug":"\u672F\u8BED"},{"level":2,"title":"\u521B\u5EFA\u65F6\u95F4\u5BF9\u8C61","slug":"\u521B\u5EFA\u65F6\u95F4\u5BF9\u8C61"},{"level":2,"title":"\u5B9E\u4F8B\u6210\u5458","slug":"\u5B9E\u4F8B\u6210\u5458"},{"level":2,"title":"\u65E5\u671F\u7684\u8FD0\u7B97","slug":"\u65E5\u671F\u7684\u8FD0\u7B97"}],"relativePath":"js/Date.md","lastUpdated":1661212217000}'),t={name:"js/Date.md"},d=i('<h1 id="date-\u6784\u9020\u5668" tabindex="-1">Date \u6784\u9020\u5668 <a class="header-anchor" href="#date-\u6784\u9020\u5668" aria-hidden="true">#</a></h1><p><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Date" target="_blank" rel="noreferrer">MDN</a></p><h2 id="\u672F\u8BED" tabindex="-1">\u672F\u8BED <a class="header-anchor" href="#\u672F\u8BED" aria-hidden="true">#</a></h2><ol><li>\u65F6\u95F4\u5355\u4F4D</li></ol><p>\u5E74\uFF08year\uFF09 \u6708\uFF08month\uFF09 \u65E5\uFF08date\uFF09 \u65F6\uFF08hour\uFF09 \u5206\uFF08minute\uFF09 \u79D2\uFF08second\uFF09= 1000ms \u6BEB\u79D2\uFF08millisecond\uFF0Cms\uFF09= 1000 \u03BCs \u5FAE\u79D2\uFF08microsecond\uFF0C\u03BCs\uFF09= 1000 ns \u7EB3\u79D2\uFF08nanosecond\uFF0Cns\uFF09</p><ol start="2"><li>UTC \u548C GMT</li></ol><p>UTC\uFF1ACoordinated Universal Time \u534F\u8C03\u4E16\u754C\u65F6\u3002\u4EE5\u539F\u5B50\u65F6\u79D2\u957F\u4E3A\u57FA\u7840\uFF0C\u7CBE\u786E\u5230\u7EB3\u79D2\u3002 GMT\uFF1AGreenwich Mean Time \u683C\u6797\u5A01\u6CBB\u65F6\u95F4\u3002\u592A\u9633\u65F6\uFF0C\u7CBE\u786E\u5230\u6BEB\u79D2\u3002</p><p>UTC \u548C GMT \u8BEF\u5DEE\u4E0D\u8D85\u8FC7 0.9 \u79D2</p><p>GMT +0800 \u8868\u793A\u4E1C 8 \u533A</p><ol start="3"><li>\u65F6\u95F4\u6233</li></ol><p>\u6570\u5B57</p><p>1970-1-1 \u51CC\u6668 \u5230\u67D0\u4E2A\u65F6\u95F4 \u6240\u7ECF\u8FC7\u7684\u6BEB\u79D2\u6570</p><h2 id="\u521B\u5EFA\u65F6\u95F4\u5BF9\u8C61" tabindex="-1">\u521B\u5EFA\u65F6\u95F4\u5BF9\u8C61 <a class="header-anchor" href="#\u521B\u5EFA\u65F6\u95F4\u5BF9\u8C61" aria-hidden="true">#</a></h2><ul><li><p>\u76F4\u63A5\u8C03\u7528\u51FD\u6570 <code>Date()</code>\uFF08\u4E0D\u4F7F\u7528 new\uFF09\uFF0C\u5FFD\u7565\u6240\u6709\u53C2\u6570\uFF0C\u76F4\u63A5\u8FD4\u56DE\u5F53\u524D\u65F6\u95F4\u7684\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>new Date()</code> \u521B\u5EFA\u65E5\u671F\u5BF9\u8C61</p><ol><li>\u65E0\u53C2\uFF0C\u5F53\u524D\u65F6\u95F4</li><li>1 \u4E2A\u53C2\u6570\uFF0C\u53C2\u6570\u4E3A\u6570\u5B57\uFF0C\u8868\u793A\u4F20\u5165\u7684\u662F\u65F6\u95F4\u6233\uFF08\u5355\u4F4D\u6BEB\u79D2\uFF09\uFF0C\u6B63\u6570\u8868\u793A1970-1-1 \u4EE5\u540E\uFF0C\u8D1F\u6570\u8868\u793A\u4EE5\u524D\u3002</li><li>2 \u4E2A\u53C2\u6570\u4EE5\u4E0A\uFF0C\u5206\u522B\u8868\u793A\uFF1A\u5E74\u3001\u6708\u3001\u65E5\u3001\u65F6\u3001\u5206\u3001\u79D2\u3001\u6BEB\u79D2</li></ol><blockquote><p>\u6CE8\u610F\uFF1A\u6708\u4EFD\u4ECE 0 \u5F00\u59CB\u8BA1\u7B97 \u5982\u679C\u7F3A\u5931\u53C2\u6570\uFF0C\u65E5\u671F\u90E8\u5206\u9ED8\u8BA4\u4E3A 1\uFF0C\u65F6\u5206\u79D2\u9ED8\u8BA4\u4E3A 0\u3002</p><p>\u6708\u3001\u65E5\u3001\u65F6\u3001\u5206\u3001\u79D2\u3001\u6BEB\u79D2\uFF0C\u5747\u53EF\u4F20\u9012\u8D1F\u6570\uFF0C\u5982\u679C\u4F20\u9012\u8D1F\u6570\uFF0C\u4F1A\u6839\u636E\u6307\u5B9A\u65E5\u671F\u8FDB\u884C\u8BA1\u7B97\u3002</p></blockquote></li></ul><h2 id="\u5B9E\u4F8B\u6210\u5458" tabindex="-1">\u5B9E\u4F8B\u6210\u5458 <a class="header-anchor" href="#\u5B9E\u4F8B\u6210\u5458" aria-hidden="true">#</a></h2><ul><li><p><code>getDate()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u6708\u4EFD\u4E2D\u7684\u7B2C\u51E0\u5929\uFF081-31\uFF09\u3002</p></li><li><p><code>getDay()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u661F\u671F\u4E2D\u7684\u7B2C\u51E0\u5929\uFF080-6\uFF09\u30020 \u8868\u793A\u661F\u671F\u5929</p></li><li><p><code>getFullYear()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u5E74\u4EFD\uFF08\u56DB\u4F4D\u6570\u5E74\u4EFD\u65F6\u8FD4\u56DE\u56DB\u4F4D\u6570\u5B57\uFF09\u3002</p></li><li><p><code>getMonth()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u7684\u6708\u4EFD\uFF080-11\uFF09</p></li><li><p><code>getHours()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u5C0F\u65F6\uFF080-23\uFF09\u3002</p></li><li><p><code>getMinutes()</code> \u8FD4\u56DE\u6307\u5B9A\u5BF9\u8C61\u7684\u5206\u949F\uFF080-59\uFF09\u3002</p></li><li><p><code>getSeconds()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u79D2\u6570\uFF080-59\uFF09\u3002</p></li><li><p><code>getMilliseconds()</code> \u8FD4\u56DE\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u6BEB\u79D2\uFF080-999\uFF09\u3002</p></li><li><p><code>getTime()</code> \u8FD4\u56DE\u65F6\u95F4\u6233\uFF0C\u5373\u4ECE1970-1-1 00:00:00 UTC\uFF08\u534F\u8C03\u4E16\u754C\u65F6\uFF09\u5230\u8BE5\u65E5\u671F\u7ECF\u8FC7\u7684\u6BEB\u79D2\u6570\uFF0C\u5BF9\u4E8E1970-1-1 00:00:00 UTC\u4E4B\u524D\u7684\u65F6\u95F4\u8FD4\u56DE\u8D1F\u503C\u3002</p></li><li><p><code>setDate()</code> \u8BBE\u7F6E\u65E5\u671F\uFF0C\u4E3A\u6307\u5B9A\u7684\u65E5\u671F\u5BF9\u8C61\u8BBE\u7F6E\u6708\u4EFD\u4E2D\u7684\u7B2C\u51E0\u5929\u3002</p></li><li><p><code>setFullYear()</code> \u8BBE\u7F6E\u5E74\u4EFD</p></li><li><p><code>setMonth()</code> \u8BBE\u7F6E\u6708\u4EFD\uFF0C\u4ECE0\u5F00\u59CB\u8BA1\u7B97\u3002</p></li><li><p><code>setHours()</code> \u8BBE\u7F6E\u5C0F\u65F6</p></li><li><p><code>setMinutes()</code> \u8BBE\u7F6E\u5206\u949F</p></li><li><p><code>setSeconds()</code> \u8BBE\u7F6E\u79D2</p></li><li><p><code>setmillisecond()</code> \u8BBE\u7F6E\u6BEB\u79D2</p></li><li><p><code>setTime()</code> \u8BBE\u7F6E\u65F6\u95F4\u6233\uFF0C\u901A\u8FC7\u6307\u5B9A\u4ECE 1970-1-1 00:00:00 UTC \u5F00\u59CB\u7ECF\u8FC7\u7684\u6BEB\u79D2\u6570\u6765\u8BBE\u7F6E\u65E5\u671F\u5BF9\u8C61\u7684\u65F6\u95F4\uFF0C\u5BF9\u4E8E\u65E9\u4E8E 1970-1-1 00:00:00 UTC\u7684\u65F6\u95F4\u53EF\u4F7F\u7528\u8D1F\u503C\u3002</p></li><li><p><code>toDateString()</code> \u5C06\u6307\u5B9A\u65E5\u671F\u5BF9\u8C61\u7684\u65E5\u671F\u90E8\u5206\u8F6C\u6362\u4E3A\u53EF\u8BFB\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>toISOString()</code> \u628A\u4E00\u4E2A\u65E5\u671F\u8F6C\u6362\u4E3A\u7B26\u5408 ISO 8601 \u6269\u5C55\u683C\u5F0F\u7684\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>toLocaleDateString()</code> \u6839\u636E\u5F53\u524D\u7CFB\u7EDF\u7684\u5730\u533A\u8BBE\u7F6E\uFF0C\u5C06\u65E5\u671F\u90E8\u5206\u8F6C\u6362\u4E3A\u53EF\u8BFB\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>toLocaleString()</code> \u6839\u636E\u5F53\u524D\u7CFB\u7EDF\u7684\u5730\u533A\u8BBE\u7F6E\uFF0C\u5C06\u6574\u4E2A\u65E5\u671F\u5BF9\u8C61\u8F6C\u4E3A\u53EF\u8BFB\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>toLocaleTimeString()</code> \u6839\u636E\u5F53\u524D\u7CFB\u7EDF\u7684\u5730\u533A\u8BBE\u7F6E\uFF0C\u5C06\u65F6\u95F4\u90E8\u5206\u8F6C\u4E3A\u53EF\u8BFB\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>valueOf()</code> \u8FD4\u56DE\u65F6\u95F4\u6233\u3002\u5F97\u5230\u65E5\u671F\u5BF9\u8C61\u7684\u539F\u59CB\u503C\uFF0C\u5373\u4ECE1970\u5E741\u67081\u65E50\u65F60\u52060\u79D2\uFF08UTC\uFF0C\u5373\u534F\u8C03\u4E16\u754C\u65F6\uFF09\u5230\u8BE5\u65E5\u671F\u7684\u6BEB\u79D2\u6570\u3002</p></li></ul><h2 id="\u65E5\u671F\u7684\u8FD0\u7B97" tabindex="-1">\u65E5\u671F\u7684\u8FD0\u7B97 <a class="header-anchor" href="#\u65E5\u671F\u7684\u8FD0\u7B97" aria-hidden="true">#</a></h2><p>\u65E5\u671F\u5BF9\u8C61\u91CD\u5199\u4E86<strong>Object</strong>\u4E2D\u7684<code>valueOf</code>\u65B9\u6CD5\uFF0C\u8FD4\u56DE\u7684\u662F\u4E00\u4E2A\u6570\u5B57\uFF0C\u8868\u793A\u65F6\u95F4\u6233</p>',18),a=[d];function c(p,r,s,n,h,u){return o(),l("div",null,a)}const T=e(t,[["render",c]]);export{g as __pageData,T as default};
